// GinServerOptions provides options for the Gin server.
type GinServerOptions struct {
	BaseURL      string
	Middlewares  []MiddlewareFunc
	ErrorHandler func(*gin.Context, error, int)
}

// RegisterHandlers creates http.Handler with routing matching OpenAPI spec.
func RegisterHandlers(router gin.IRouter, si ServerInterface) {
	RegisterHandlersWithOptions(router, si, GinServerOptions{})
}

// RegisterHandlersWithOptions creates http.Handler with additional options
func RegisterHandlersWithOptions(router gin.IRouter, si ServerInterface, options GinServerOptions) {
	errorHandler := options.ErrorHandler
	if errorHandler == nil {
		errorHandler = func(c *gin.Context, err error, statusCode int) {
			c.JSON(statusCode, gin.H{"msg": err.Error()})
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandler:       errorHandler,
	}

	router.GET(options.BaseURL+"/agent-profiles", wrapper.GetAgentProfiles)
	router.POST(options.BaseURL+"/agent-profiles", wrapper.PostAgentProfiles)
	router.GET(options.BaseURL+"/audit-logs", wrapper.GetAuditLogs)
	router.POST(options.BaseURL+"/auth/login", wrapper.Login)
	router.POST(options.BaseURL+"/auth/logout", wrapper.Logout)
	router.GET(options.BaseURL+"/auth/me", wrapper.GetCurrentAdministrator)
	router.GET(options.BaseURL+"/events/stream", wrapper.StreamEvents)
	router.GET(options.BaseURL+"/github/app", wrapper.GetGitHubApp)
	router.PUT(options.BaseURL+"/github/app", wrapper.PutGitHubApp)
	router.GET(options.BaseURL+"/github/app/manifest", wrapper.GetGitHubAppManifest)
	router.GET(options.BaseURL+"/github/app/manifest/callback", wrapper.GithubAppManifestCallback)
	router.GET(options.BaseURL+"/installations", wrapper.GetInstallations)
	router.POST(options.BaseURL+"/internal/v1/tools/call", wrapper.CallInternalTool)
	router.GET(options.BaseURL+"/jobs", wrapper.GetJobs)
	router.GET(options.BaseURL+"/repo-caches", wrapper.GetRepoCaches)
	router.GET(options.BaseURL+"/repositories", wrapper.GetRepositories)
	router.POST(options.BaseURL+"/repositories", wrapper.CreateRepository)
	router.GET(options.BaseURL+"/settings/agent-provider", wrapper.GetAgentProviderSettings)
	router.PUT(options.BaseURL+"/settings/agent-provider", wrapper.PutAgentProviderSettings)
	router.POST(options.BaseURL+"/setup/admin", wrapper.SetupAdministrator)
	router.GET(options.BaseURL+"/setup/status", wrapper.GetSetupStatus)
	router.GET(options.BaseURL+"/system/status", wrapper.GetSystemStatus)
	router.GET(options.BaseURL+"/threads", wrapper.GetThreads)
	router.GET(options.BaseURL+"/trigger-rules", wrapper.GetTriggerRules)
	router.POST(options.BaseURL+"/trigger-rules", wrapper.PostTriggerRules)
	router.POST(options.BaseURL+"/webhooks/github", wrapper.ReceiveGitHubWebhook)
	router.GET(options.BaseURL+"/work-items", wrapper.GetWorkItems)
	router.GET(options.BaseURL+"/workers", wrapper.GetWorkers)
	router.GET(options.BaseURL+"/worktrees", wrapper.GetWorktrees)
}

